1	/**
2	 * The Loom — unit tests.
3	 *
4	 * Tests weave() with role → permissions → tool resolution via a mock
5	 * Instrumentarium, and the basic structural contract.
6	 */
7	
8	import { describe, it, beforeEach, afterEach } from 'node:test';
9	import assert from 'node:assert/strict';
10	import fs from 'node:fs';
11	import os from 'node:os';
12	import path from 'node:path';
13	import { z } from 'zod';
14	
15	import { setGuild, clearGuild } from '@shardworks/nexus-core';
16	import { tool, type InstrumentariumApi, type ResolvedTool, type ResolveOptions } from '@shardworks/tools-apparatus';
17	
18	import { createLoom, type LoomApi, type LoomConfig } from './loom.ts';
19	import loomDefault from './index.ts';
20	
21	// ── Test fixtures ───────────────────────────────────────────────────
22	
23	/** A minimal tool for testing. */
24	function testTool(name: string, permission?: string) {
25	  return tool({
26	    name,
27	    description: `Test tool: ${name}`,
28	    params: {},
29	    handler: async () => ({ ok: true }),
30	    ...(permission !== undefined ? { permission } : {}),
31	  });
32	}
33	
34	/** A mock Instrumentarium that records calls and returns configured tools. */
35	function mockInstrumentarium(resolvedTools: ResolvedTool[] = []) {
36	  const calls: ResolveOptions[] = [];
37	  const api: InstrumentariumApi = {
38	    resolve(options: ResolveOptions): ResolvedTool[] {
39	      calls.push(options);
40	      return resolvedTools;
41	    },
42	    find: () => null,
43	    list: () => resolvedTools,
44	  };
45	  return { api, calls };
46	}
47	
48	/** Set up a fake guild with the given loom config and apparatus map. */
49	function setupGuild(opts: {
50	  loomConfig?: LoomConfig;
51	  apparatuses?: Record<string, unknown>;
52	  home?: string;
53	}) {
54	  const apparatuses = opts.apparatuses ?? {};
55	  setGuild({
56	    home: opts.home ?? '/tmp/test-guild',
57	    apparatus: <T>(id: string): T => {
58	      const a = apparatuses[id];
59	      if (!a) throw new Error(`Apparatus '${id}' not installed`);
60	      return a as T;
61	    },
62	    guildConfig: () => ({
63	      name: 'test-guild',
64	      nexus: '0.0.0',
65	      workshops: {},
66	      plugins: [],
67	      loom: opts.loomConfig,
68	    }),
69	    kits: () => [],
70	    apparatuses: () => [],
71	  } as never);
72	}
73	
74	/** Create a started Loom and return its API. */
75	function startLoom(): LoomApi {
76	  const plugin = createLoom();
77	  const apparatus = (plugin as { apparatus: { start: (ctx: unknown) => void; provides: unknown } }).apparatus;
78	  apparatus.start({ on: () => {} });
79	  return apparatus.provides as LoomApi;
80	}
81	
82	// ── Tests ────────────────────────────────────────────────────────────
83	
84	describe('The Loom', () => {
85	  afterEach(() => {
86	    clearGuild();
87	  });
88	
89	  describe('createLoom()', () => {
90	    it('returns a plugin with apparatus shape', () => {
91	      const plugin = createLoom();
92	      assert.ok('apparatus' in plugin, 'should have apparatus key');
93	
94	      const { apparatus } = plugin as { apparatus: Record<string, unknown> };
95	      assert.deepStrictEqual(apparatus.requires, ['tools']);
96	      assert.ok(apparatus.provides, 'should have provides');
97	      assert.ok(typeof apparatus.start === 'function', 'should have start()');
98	    });
99	
100	    it('provides a LoomApi with weave()', () => {
101	      const plugin = createLoom();
102	      const api = (plugin as { apparatus: { provides: LoomApi } }).apparatus.provides;
103	      assert.ok(typeof api.weave === 'function');
104	    });
105	  });
106	
107	  describe('default export', () => {
108	    it('is a plugin with apparatus shape', () => {
109	      assert.ok('apparatus' in loomDefault, 'default export should have apparatus key');
110	      const { apparatus } = loomDefault as { apparatus: Record<string, unknown> };
111	      assert.ok(apparatus.provides, 'should have provides');
112	      assert.ok(typeof (apparatus.provides as LoomApi).weave === 'function', 'provides should have weave()');
113	    });
114	  });
115	
116	  describe('weave() — no role', () => {
117	    it('returns undefined systemPrompt', async () => {
118	      setupGuild({});
119	      const api = startLoom();
120	      const weave = await api.weave({});
121	      assert.strictEqual(weave.systemPrompt, undefined);
122	    });
123	
124	    it('returns undefined tools when no role is provided', async () => {
125	      setupGuild({});
126	      const api = startLoom();
127	      const weave = await api.weave({});
128	      assert.strictEqual(weave.tools, undefined);
129	    });
130	
131	    it('returns a promise', () => {
132	      setupGuild({});
133	      const api = startLoom();
134	      const result = api.weave({});
135	      assert.ok(result instanceof Promise, 'weave() should return a Promise');
136	    });
137	
138	    it('returns an object without initialPrompt', async () => {
139	      setupGuild({});
140	      const api = startLoom();
141	      const weave = await api.weave({ role: 'artificer' });
142	      assert.ok(!('initialPrompt' in weave), 'AnimaWeave should not have initialPrompt');
143	    });
144	
145	    it('returns undefined environment when no role is provided', async () => {
146	      setupGuild({});
147	      const api = startLoom();
148	      const weave = await api.weave({});
149	      assert.strictEqual(weave.environment, undefined);
150	    });
151	  });
152	
153	  describe('weave() — role with tool resolution', () => {
154	    it('resolves tools for a configured role', async () => {
155	      const readTool = testTool('stack-query', 'read');
156	      const resolved: ResolvedTool[] = [
157	        { definition: readTool, pluginId: 'stacks' },
158	      ];
159	      const { api: instrumentarium, calls } = mockInstrumentarium(resolved);
160	
161	      setupGuild({
162	        loomConfig: {
163	          roles: {
164	            scribe: {
165	              permissions: ['stacks:read'],
166	            },
167	          },
168	        },
169	        apparatuses: { tools: instrumentarium },
170	      });
171	
172	      const api = startLoom();
173	      const weave = await api.weave({ role: 'scribe' });
174	
175	      assert.equal(weave.tools?.length, 1);
176	      assert.equal(weave.tools![0]!.definition.name, 'stack-query');
177	
178	      // Verify the Instrumentarium was called with correct args
179	      assert.equal(calls.length, 1);
180	      assert.deepStrictEqual(calls[0]!.permissions, ['stacks:read']);
181	      assert.equal(calls[0]!.caller, 'anima');
182	    });
183	
184	    it('passes strict flag from role definition', async () => {
185	      const { api: instrumentarium, calls } = mockInstrumentarium([]);
186	
187	      setupGuild({
188	        loomConfig: {
189	          roles: {
190	            scribe: {
191	              permissions: ['stacks:read'],
192	              strict: true,
193	            },
194	          },
195	        },
196	        apparatuses: { tools: instrumentarium },
197	      });
198	
199	      const api = startLoom();
200	      await api.weave({ role: 'scribe' });
201	
202	      assert.equal(calls[0]!.strict, true);
203	    });
204	
205	    it('returns undefined tools for an unknown role', async () => {
206	      const { api: instrumentarium, calls } = mockInstrumentarium([]);
207	
208	      setupGuild({
209	        loomConfig: {
210	          roles: {
211	            artificer: { permissions: ['*:*'] },
212	          },
213	        },
214	        apparatuses: { tools: instrumentarium },
215	      });
216	
217	      const api = startLoom();
218	      const weave = await api.weave({ role: 'unknown-role' });
219	
220	      assert.strictEqual(weave.tools, undefined);
221	      assert.equal(calls.length, 0, 'should not call instrumentarium for unknown role');
222	    });
223	
224	    it('returns undefined tools when no roles configured', async () => {
225	      const { api: instrumentarium, calls } = mockInstrumentarium([]);
